#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int A, B;
        scanf("%d %d", &A, &B);
        int min = (A > B) ? A : B;
        int max = A + B;
        printf("%d %d\n", min, max);
    }
    return 0;
}

